query:
-- Get count of archived sessions before deletion
SELECT COUNT(*) as archived_count FROM live_qa_session_metadata WHERE isLive = false;

-- Delete all related data for archived sessions
DELETE FROM live_qa_questions 
WHERE sessionId IN (
  SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false
);

DELETE FROM transcript_segments 
WHERE sessionId IN (
  SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false
);

DELETE FROM session_notes 
WHERE sessionId IN (
  SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false
);

-- Delete all archived sessions
DELETE FROM live_qa_session_metadata WHERE isLive = false;

-- Create audit record with timestamp
INSERT INTO audit_log (action, entity_type, entity_id, timestamp, details) 
VALUES (
  'ARCHIVE_PURGE',
  'sessions',
  'all_archived',
  NOW(),
  'All archived sessions permanently deleted from Shadow Mode'
);

-- Verify deletion
SELECT COUNT(*) as remaining_sessions FROM live_qa_session_metadata WHERE isLive = false;

